for (initialization; condition; increment)
{
    // runs once per repetition
}

#include <iostream>

using namespace std;

int main()
{
    for (int i = 1; i <= 5; i++)
    {
        cout << i << endl;
    }

    return 0;
}

for (int i = 1; i < 5; i++)
{
    cout << i << endl;
}

for (int i = 1; i <= 5; i--) // wrong direction!
{
    cout << i << endl;
}

for (int i = 5; i >= 1; i--)
{
    cout << i << endl;
}

for (int i = 1; i <= 2; i++)
{
    for (int j = 1; j <= 2; j++)
    {
        cout << i << j << " ";
    }
}

